import time
from collections import defaultdict

class RateLimitExceeded(Exception):
    pass

class RateLimiter:
    def __init__(self, max_calls, period):
        self.max_calls = max_calls
        self.period = period
        self.calls = defaultdict(list)

    def __call__(self, key):
        now = time.time()
        self.calls[key] = [t for t in self.calls[key] if t > now - self.period]

        if len(self.calls[key]) >= self.max_calls:
            raise RateLimitExceeded("Rate limit exceeded")

        self.calls[key].append(now)
        return True

if __name__ == '__main__':
    # Örnek Kullanım
    rate_limiter = RateLimiter(max_calls=5, period=60) # 60 saniyede en fazla 5 çağrı

    user_id = "kullanici123"

    for i in range(7):
        try:
            rate_limiter(user_id)
            print(f"Çağrı {i+1}: Başarılı")
        except RateLimitExceeded:
            print(f"Çağrı {i+1}: Hız Sınırı Aşıldı!")
        time.sleep(5)
